#include <oesdk/ipc.h>
OesdkStatus OesdkEndpointBind(OesdkChannel*C,OesdkRights R,OesdkEndpoint*E){if(C==NULL||E==NULL)return OESDK_STATUS_INVALID_ARGUMENT;*E=(OesdkEndpoint){C,R};return OESDK_STATUS_SUCCESS;}OesdkStatus OesdkEndpointSend(OesdkEndpoint*E,const OesdkIpcMessage*M){if(E==NULL||M==NULL||E->Channel==NULL||(E->Rights&OESDK_RIGHT_WRITE)==0U)return OESDK_STATUS_INVALID_ARGUMENT;if(M->Size>OESDK_IPC_PAYLOAD_MAX)return OESDK_STATUS_INVALID_ARGUMENT;if(M->HasCapability&&(E->Rights&OESDK_RIGHT_TRANSFER)==0U)return OESDK_STATUS_INVALID_ARGUMENT;if(E->Channel->Count==OESDK_CHANNEL_DEPTH)return OESDK_STATUS_BUSY;E->Channel->Queue[E->Channel->WriteIndex]=*M;E->Channel->WriteIndex=(E->Channel->WriteIndex+1U)%OESDK_CHANNEL_DEPTH;++E->Channel->Count;return OESDK_STATUS_SUCCESS;}OesdkStatus OesdkEndpointReceive(OesdkEndpoint*E,OesdkIpcMessage*M){if(E==NULL||M==NULL||E->Channel==NULL||(E->Rights&OESDK_RIGHT_READ)==0U)return OESDK_STATUS_INVALID_ARGUMENT;if(E->Channel->Count==0U)return OESDK_STATUS_NOT_FOUND;*M=E->Channel->Queue[E->Channel->ReadIndex];E->Channel->ReadIndex=(E->Channel->ReadIndex+1U)%OESDK_CHANNEL_DEPTH;--E->Channel->Count;return OESDK_STATUS_SUCCESS;}
